      series={[
        { type: 'bar', stack: 'total', data: [320, 302, 301, 334], name: 'Product A' },
        { type: 'bar', stack: 'total', data: [120, 132, 101, 134], name: 'Product B' },
      ]}
    >
      <Title text="Quarterly Revenue" />
      <Legend />
      <Tooltip />
    </BarChart>
  ),
};

